package com.anvritai.abhay.api;
import static com.anvritai.abhay.api.SettingsDtos.*;import com.anvritai.abhay.security.UserPrincipal;import com.anvritai.abhay.service.CompanySettingsService;import jakarta.validation.Valid;import java.util.*;import org.springframework.security.core.annotation.AuthenticationPrincipal;import org.springframework.web.bind.annotation.*;
@RestController @RequestMapping("/api/companies/{companyId}/settings") public class CompanySettingsController{private final CompanySettingsService service;public CompanySettingsController(CompanySettingsService s){service=s;}@GetMapping public List<SettingResponse> list(@AuthenticationPrincipal UserPrincipal p,@PathVariable UUID companyId,@RequestParam(required=false)String category){return service.list(p.id(),companyId,category);}@PutMapping("/{category}") public SettingResponse put(@AuthenticationPrincipal UserPrincipal p,@PathVariable UUID companyId,@PathVariable String category,@Valid @RequestBody SettingRequest r){return service.put(p.id(),companyId,category,r);}}
